// `require('internal/test/snapshot')` — port of Node.js v26.3.0's
// lib/internal/test_runner/snapshot.js. Consumed by `node:test` for
// `t.assert.snapshot()` / `t.assert.fileSnapshot()` and by the
// `--expose-internals` shim, which serves it as
// `internal/test_runner/snapshot` for vendored node tests.
const { kEmptyObject } = require("internal/shared");
const { validateArray, validateFunction, validateObject, validateString } = require("internal/validators");
const { strictEqual } = require("node:assert");

const kMissingSnapshotTip =
  "Missing snapshots can be generated by rerunning the command with the --test-update-snapshots flag.";

function jsonSerializer(value: unknown) {
  return JSON.stringify(value, null, 2);
}
const defaultSerializers = [jsonSerializer];

function defaultResolveSnapshotPath(testPath: string) {
  if (typeof testPath !== "string") return testPath;
  return `${testPath}.snapshot`;
}

let resolveSnapshotPathFn: (testPath: string) => string = defaultResolveSnapshotPath;
let serializerFns: Function[] = defaultSerializers;

function setResolveSnapshotPath(fn: (testPath: string) => string) {
  validateFunction(fn, "fn");
  resolveSnapshotPathFn = fn;
}

function setDefaultSnapshotSerializers(serializers: Function[]) {
  validateFunctionArray(serializers, "serializers");
  serializerFns = serializers.slice();
}

function validateFunctionArray(fns: unknown, name: string) {
  validateArray(fns, name);
  const array = fns as unknown[];
  for (let i = 0; i < array.length; ++i) validateFunction(array[i], `${name}[${i}]`);
}

function templateEscape(str: unknown) {
  return String(str).replaceAll("\\", "\\\\").replaceAll("`", "\\`").replaceAll("${", "\\${");
}

function escapeSnapshotKey(str: string) {
  return JSON.stringify(str, null, 2).slice(1, -1).replaceAll("`", "\\`").replaceAll("${", "\\${");
}

function throwReadError(err: unknown, filename: string): never {
  let msg = `Cannot read snapshot file '${filename}.'`;
  if ((err as { code?: string })?.code === "ENOENT") msg += ` ${kMissingSnapshotTip}`;
  const error = $ERR_INVALID_STATE(msg);
  error.cause = err;
  error.filename = filename;
  throw error;
}

function throwWriteError(err: unknown, filename: string): never {
  const error = $ERR_INVALID_STATE(`Cannot write snapshot file '${filename}.'`);
  error.cause = err;
  error.filename = filename;
  throw error;
}

function throwSerializationError(input: unknown, err: unknown): never {
  const error = $ERR_INVALID_STATE("The provided serializers did not generate a string.");
  error.input = input;
  error.cause = err;
  throw error;
}

function serializeValue(value: unknown, serializers: Function[]) {
  let v = value;
  for (let i = 0; i < serializers.length; ++i) v = serializers[i](v);
  return v;
}

class SnapshotFile {
  snapshotFile: string;
  snapshots: Record<string, unknown>;
  nameCounts: Map<string, number>;
  loaded: boolean;

  constructor(snapshotFile: string) {
    this.snapshotFile = snapshotFile;
    this.snapshots = { __proto__: null } as unknown as Record<string, unknown>;
    this.nameCounts = new Map();
    this.loaded = false;
  }

  getSnapshot(id: string) {
    if (!(id in this.snapshots)) {
      const err = $ERR_INVALID_STATE(`Snapshot '${id}' not found in '${this.snapshotFile}.' ${kMissingSnapshotTip}`);
      err.snapshot = id;
      err.filename = this.snapshotFile;
      throw err;
    }
    return this.snapshots[id];
  }

  setSnapshot(id: string, value: unknown) {
    this.snapshots[escapeSnapshotKey(id)] = value;
  }

  nextId(name: string) {
    const count = this.nameCounts.$get(name) ?? 1;
    this.nameCounts.$set(name, count + 1);
    return `${name} ${count}`;
  }

  readFile() {
    if (this.loaded) return;
    const { readFileSync } = require("node:fs");
    const { createContext, runInContext } = require("node:vm");
    try {
      const source = readFileSync(this.snapshotFile, "utf8");
      const context = { __proto__: null, exports: { __proto__: null } };
      createContext(context);
      runInContext(source, context);

      if (context.exports === null || typeof context.exports !== "object") {
        throw $ERR_INVALID_STATE(`Malformed snapshot file '${this.snapshotFile}'.`);
      }

      for (const key in context.exports) {
        this.snapshots[key] = templateEscape(context.exports[key]);
      }
      this.loaded = true;
    } catch (err) {
      throwReadError(err, this.snapshotFile);
    }
  }

  writeFile() {
    const { mkdirSync, writeFileSync } = require("node:fs");
    const { dirname } = require("node:path");
    try {
      const keys = Object.keys(this.snapshots).sort();
      const output = keys.map(key => `exports[\`${key}\`] = \`${this.snapshots[key]}\`;\n`).join("\n");
      mkdirSync(dirname(this.snapshotFile), { __proto__: null, recursive: true });
      writeFileSync(this.snapshotFile, output, "utf8");
    } catch (err) {
      throwWriteError(err, this.snapshotFile);
    }
  }
}

class SnapshotManager {
  updateSnapshots: boolean;
  cache: Map<string, SnapshotFile>;

  constructor(updateSnapshots: boolean) {
    this.updateSnapshots = updateSnapshots;
    this.cache = new Map();
  }

  resolveSnapshotFile(entryFile: string) {
    let snapshotFile = this.cache.$get(entryFile);

    if (snapshotFile === undefined) {
      const resolved = resolveSnapshotPathFn(entryFile);
      if (typeof resolved !== "string") {
        const err = $ERR_INVALID_STATE("Invalid snapshot filename.");
        err.filename = resolved;
        throw err;
      }
      snapshotFile = new SnapshotFile(resolved);
      snapshotFile.loaded = this.updateSnapshots;
      this.cache.$set(entryFile, snapshotFile);
    }

    return snapshotFile;
  }

  serialize(input: unknown, serializers: Function[] = serializerFns) {
    try {
      return `\n${templateEscape(serializeValue(input, serializers))}\n`;
    } catch (err) {
      throwSerializationError(input, err);
    }
  }

  serializeWithoutEscape(input: unknown, serializers: Function[] = serializerFns) {
    try {
      return serializeValue(input, serializers);
    } catch (err) {
      throwSerializationError(input, err);
    }
  }

  writeSnapshotFiles() {
    if (!this.updateSnapshots) return;
    for (const snapshotFile of this.cache.values()) snapshotFile.writeFile();
  }

  createAssert() {
    const manager = this;

    return function snapshotAssertion(
      this: any,
      actual: unknown,
      options: { serializers?: Function[] } = kEmptyObject,
    ) {
      validateObject(options, "options");
      const { serializers = serializerFns } = options;
      validateFunctionArray(serializers, "options.serializers");
      const { filePath, fullName } = this;
      const snapshotFile = manager.resolveSnapshotFile(filePath);
      const value = manager.serialize(actual, serializers);
      const id = snapshotFile.nextId(fullName);

      if (manager.updateSnapshots) {
        snapshotFile.setSnapshot(id, value);
      } else {
        snapshotFile.readFile();
        strictEqual(value, snapshotFile.getSnapshot(id));
      }
    };
  }

  createFileAssert() {
    const manager = this;

    return function fileSnapshotAssertion(
      actual: unknown,
      path: string,
      options: { serializers?: Function[] } = kEmptyObject,
    ) {
      validateString(path, "path");
      validateObject(options, "options");
      const { serializers = serializerFns } = options;
      validateFunctionArray(serializers, "options.serializers");
      const value = manager.serializeWithoutEscape(actual, serializers);
      const { mkdirSync, readFileSync, writeFileSync } = require("node:fs");

      if (manager.updateSnapshots) {
        try {
          mkdirSync(require("node:path").dirname(path), { __proto__: null, recursive: true });
          writeFileSync(path, value, "utf8");
        } catch (err) {
          throwWriteError(err, path);
        }
        return;
      }

      let expected;
      try {
        expected = readFileSync(path, "utf8");
      } catch (err) {
        throwReadError(err, path);
      }
      strictEqual(value, expected);
    };
  }
}

export default {
  SnapshotManager,
  defaultResolveSnapshotPath,
  defaultSerializers,
  setDefaultSnapshotSerializers,
  setResolveSnapshotPath,
};
